export const meta = {
  name: 'sloe-reconcile-overlap',
  description: 'Merge my parity-fix sweep into the aubergine redesign for the 15 overlap files. Per file: 3-way human-merge (aubergine current vs my-snapshot vs clay-base) — port ONLY the gap-fixes aubergine still lacks, never downgrade aubergine.',
  phases: [{ title: 'Reconcile', detail: 'one agent per overlap cluster, 3-way merge' }],
}

const CLUSTERS = [{"key":"whats-new","model":"sonnet","files":["app/whats-new/page.tsx","apps/mobile/app/whats-new.tsx","apps/mobile/tests/unit/whatsNewScreen.test.tsx"],"gaps":[{"c":"functionality","s":5,"i":"Release date renders ONE DAY EARLY. Capture shows '11 May 2026' but the entry's releaseDate is '2026-05-12'. `new Date('2026-05-12')` parses as UTC midnight, then toLocaleDateString renders in the device's local TZ — on any timezone west of UTC it shifts back a day (reproduced: TZ=America/Los_Angeles → '11 May 2026'). Shipping a wrong release date on the 'what's new' surface is a credibility hit on a premium app.","f":"Parse as a local calendar date, not UTC. In formatReleaseDate, split the ISO ('2026-05-12'.split('-')) and build `new Date(y, m-1, d)`, or append a time without Z. Identical bug + fix exists in app/whats-new/page.tsx (web) — fix both in the same commit. Add a TZ-pinned unit test (the CLAUDE.md date-dependent-test note applies)."},{"c":"typography","s":4,"i":"No serif anywhere. The build label 'Build 49 (1.0.7 #49)' is Inter 20pt/700 (buildTitle) and the nav title 'What's new' is the default iOS system sans title. Design system §2.3 mandates Fraunces for screen titles and for any number that is the focus of a card (the build label is an achievement-grade headline → display-section/subtitle, Fraunces 17-22pt 600). The whole screen is sans — it loses the 'editorial cookbook' register that is the entire premium thesis.","f":"Set buildTitle to Fraunces (fontFamily serif token), ~20-22pt weight 600. Set the native-stack headerTitle to a Fraunces Text component (headerTitle render prop) so the nav bar reads editorial. Verify the font actually loaded in a fresh sim capture (system serif fallback is Georgia — design system §2.1)."},{"c":"spacing","s":4,"i":"Multiple off-scale values in the row primitive. itemRow uses `paddingVertical: 12` and `gap: 10` (between bullet and text); the release headline uses `marginTop: 6`; sectionHeading uses `marginBottom: 8` raw. The canonical Spacing scale (constants/theme.ts) is 4/8/16/20/24/32/40 — 12, 10 and 6 are NOT on it. The 12pt row padding is the most visible: rows read slightly cramped vs the 16pt card-padding rhythm used by headerCard.","f":"paddingVertical: 12 → Spacing.md (16) for breathing room, or Spacing.sm (8)+ if you want denser — pick one on-scale. gap: 10 → Spacing.sm (8). marginTop: 6 (release headline) → Spacing.xs (4). marginBottom: 8 → Spacing.sm. Replace every raw literal with a Spacing token so the screen passes the spacing lens."},{"c":"parity","s":4,"i":"Mobile shows ONLY the latest build's entry; web (app/whats-new/page.tsx) renders ALL releases as a scrolling timeline with per-release headers, a 'Latest' chip, and an RSS subscribe link. Same SSOT, fundamentally different information architecture. A user who taps the same link on each platform sees a single card on iOS and a full release history on web.","f":"Decide the canonical IA and apply to both. Recommended: mobile maps the same getAllChangelogs() timeline (it already imports getLatestChangelog only). Either add the timeline to mobile or trim web to latest-only — but they must agree. Update the mobile file's own header comment which claims the surfaces 'render the exact same entry' (no longer true)."},{"c":"style","s":3,"i":"Kind is not differentiated on mobile. NEW / FIXED / COMING SOON all use the same plum bullet (accent.primary) and the same plain uppercase Inter heading, so the only signal separating sections is the heading text. Web colour-codes each kind (emerald/sky/amber chips + matching bullets) giving far stronger scannable hierarchy. Mobile hierarchy reads flat.","f":"Differentiate the three kinds on mobile — at minimum a kind chip (like web's) using the LOCKED in-app semantic palette: NEW → success sage, FIXED → a neutral/info treatment, COMING SOON → amber (§1.2). Keep bullets a single accent if you prefer restraint, but the section label should carry a coloured chip, not bare uppercase text. (Do NOT copy web's raw emerald/sky/amber Tailwind — map to the in-app tokens.)"},{"c":"style","s":3,"i":"The screen is a flat bordered list with no depth or editorial chrome — generic iOS-changelog feel, not Sloe. headerCard and sectionCard are warm cards (good) but carry only a 1px border and no shadow; the design system §5 specifies a hairline border PLUS a soft shadow (0 1px 4px rgba(27,24,20,0.06) / iOS shadowOpacity 0.06) for cards on the white base. Without the shadow the cards sit dead-flat on the page.","f":"Add the standard card shadow (shadowColor #1B1814, shadowOpacity 0.06, shadowRadius 4, shadowOffset {0,1}, elevation 2) to headerCard and sectionCard. Consider a subtle Fraunces serif build-label + a thin accent rule under the header to lift it above 'system list'."},{"c":"photography","s":2,"i":"Zero imagery. The surface is text-only. The design system imagery rules (§11) and the editorial-cookbook thesis mean a premium 'what's new' could carry a small warm editorial header treatment (e.g. a hairline-framed monogram or a muted dish/ingredient motif) to feel like Sloe rather than a plist dump. Currently it's indistinguishable from any utilitarian app's changelog.","f":"Add a restrained brand/editorial element to the header card — a small Sloe mark or a single muted ingredient single-subject (§11.1 pipeline) — OR accept text-only as an intentional, documented choice and note it so it doesn't read as an omission. Recommend the former for premium parity; do not leave it cold/empty."},{"c":"parity","s":2,"i":"Web background is a slate-50→white→slate-50 gradient (`bg-gradient-to-br from-slate-50 via-white to-slate-50`), violating design system §0 constraint 1 (white base #FFFFFF everywhere in-app; no page wash). Mobile correctly uses colors.background (white). The two grounds diverge and web breaks the locked white-base rule. (Flagging as ground/structure, not accent direction.)","f":"Web: drop the slate gradient wrapper, use white base (bg-white / --background) to match mobile and §0. Keep dark-mode handling via the documented token, not a hardcoded slate gradient."},{"c":"typography","s":2,"i":"Section heading letterSpacing is a raw 1.1 with textTransform uppercase at 12pt/700. The design system section-eyebrow spec is Inter 10-11pt, weight 600, letter-spacing +0.08em, sage colour. 12pt/700/1.1px is heavier and tighter than the eyebrow token — slightly off-ramp.","f":"Align sectionHeading to the section-eyebrow token: ~11pt, weight 600, letterSpacing ≈0.9 (0.08em of 11pt), colour textSecondary (sage). Minor, but it's the one eyebrow on the screen and should match the ramp exactly."},{"c":"style","s":1,"i":"Bullet dots are 6×6pt plum filled circles at marginTop 7 — fine, but with the long multi-line item text (15pt/21 line-height) and 12pt row padding, the dot-to-text relationship and the flat divider list make long entries (e.g. the multi-sentence 'Weight chart on Progress…') hard to scan. Reads as a wall of bullets rather than a curated set of upgrades.","f":"Once kind chips + on-scale padding land, this largely resolves. Optionally tighten itemText lineHeight to the body-primary token (15pt → ~22) and keep the bullet aligned to the first line cap-height (marginTop on-scale, e.g. 6→ derive from line-height rather than a magic 7)."}]},{"key":"import-shared","model":"opus","files":["apps/mobile/app/import-shared.tsx","apps/mobile/.maestro/25_import_shared.yaml","apps/mobile/e2e/25-import-shared.test.ts"],"gaps":[{"c":"style","s":5,"i":"Entire idle flow (wordmark, title, body, paste field, Import button, Use clipboard, Import from photo) is crammed into ONE monolithic cream panelCard slab (borderRadius 24, border + 40px padding). The spec §3.2 wants a header + paste-field-on-white + source-trust-chip row + RECENT IMPORTS as DISTINCT sections sitting on the white page ground. The single boxed slab reads as a placeholder modal, not a premium editorial import surface — it is the dominant reason this surface feels 'rough' not 'premium'.","f":"Unbox the idle state: render the header (Sloe mark + serif title + body) and the paste field directly on white #FFFFFF per §3.2. Reserve the cream #F6F5F2 card for the paste field fill only (56px, Radius 12). Move 'Import from photo'/'Use clipboard' to tertiary rows below, source chips and RECENT IMPORTS as their own sections separated by 32px (Spacing.xxl). Drop the outer panelCard wrapper for idle."},{"c":"functionality","s":5,"i":"The 'IMPORT FROM' grid (TikTok / Instagram / YouTube / Website) is a FAKE four-way router: all four tiles call onPasteFromClipboard (import-shared.tsx:2022-2025). The plum-tinted icon boxes (accent.primary + '22') make them read as four separate routes. This is audit gap #6 — a discoverability AND honesty failure flagged in import.md §3.2 and still live.","f":"Per spec §3.2: demote to a single non-tappable trust-affordance row — small #F6F5F2 chips (32×24, Radius 8) holding only the platform monogram, no onPress, with an Inter 12px sage 'Works with' label. Platform-specific guidance already surfaces via the inline hint below the field. Remove the tinted icon boxes so they stop reading as buttons."},{"c":"functionality","s":4,"i":"'Import from photo' is shown to ALL users with no Pro lock; photo OCR is Pro-gated server-side (403 pro_required), so free users tap and fail at request time. Audit gap #1, flagged in import.md §3.1/§3.7 and unresolved here.","f":"Add a Lock badge (12px amber #C9892C) + '(Pro)' Inter 12px amber on the photo affordance; route Free users to the paywall on tap, Pro users to the picker. Surface the gate before the tap, not after."},{"c":"typography","s":3,"i":"Section eyebrows 'IMPORT FROM' and 'RECENT IMPORTS' render as Inter 13px weight 600, letterSpacing 0.5, colour textSecondary (import-shared.tsx importSourcesLabel/recentLabel). The design system §2.2 section-eyebrow role wants Inter 10–11px, weight 600, +0.08em (~1.1px) tracking, uppercase, sage #7C8466. 13px at 0.5 tracking reads as a heavy sub-label, not a delicate editorial eyebrow.","f":"Drop to 11px, set letterSpacing ~1 (≈ +0.08em), colour sage; keep uppercase. Apply the same eyebrow token used elsewhere in the redesign so all caps labels are consistent."},{"c":"style","s":3,"i":"Icon set is @expo/vector-icons Ionicons (logo-tiktok, logo-instagram, logo-youtube, globe-outline, clipboard-outline, camera-outline, restaurant-outline) throughout the idle state. The locked icon rule (design-system §0.1b) says abstract controls/nav glyphs MUST be lucide line icons; brand platform logos are an acceptable exception but the generic globe/clipboard/camera/restaurant glyphs should be lucide (Link2, Clipboard, Camera, UtensilsCrossed) for system consistency. Mixed icon families read as unpolished.","f":"Migrate the non-brand glyphs to lucide-react-native (Link2/Clipboard/Camera/Globe), ink or clay active per §0.1b. Keep platform monograms for the trust-chip row only."},{"c":"spacing","s":3,"i":"Off-scale radii on the two most prominent controls: the paste input and the primary Import button both use hardcoded borderRadius: 16 (import-shared.tsx input/primaryBtn), but the mobile Radius scale tops out at xl=12 (sm4/md6/lg8/xl12/full). 16 is not a token. The spec §3.2 specifies 12px on the paste field. The panel slab itself is Radius.xl*2 = 24 (a doubled token, also non-canonical).","f":"Set the input and primary button radius to Radius.xl (12) to match the spec's 12px field and the rest of the system. If a softer pill is wanted on the CTA, use Radius.full; do not use the orphan 16."},{"c":"spacing","s":3,"i":"panelCard padding is Spacing.xxxl (40) on all sides — far looser than the standard card padding (16, Spacing.md) the design system §3.2 prescribes. Combined with the monolithic slab this produces a lot of dead cream around sparse content, amplifying the placeholder feel. The source tiles also use a raw paddingHorizontal: 8 / paddingVertical: 16 (8 is off the icon-box rhythm and was a papercut workaround for label truncation).","f":"If the slab is retained for any state, bring padding to Spacing.xl (24) max. Once the idle is unboxed (gap #1), the 40px padding disappears. Re-derive source-chip padding from the 4pt grid once they become non-interactive chips."},{"c":"photography","s":3,"i":"The idle screen has zero imagery — it is all chrome (wordmark, text, field, glyph tiles). Julienne's import/add entry leans on warm editorial framing; the design-system imagery rule (§11) calls for warm treatment over cold tiles. The source tiles are cold flat glyphs in tinted boxes. There is no editorial illustration or warm anchor, so the surface feels utilitarian rather than the 'editorial cookbook' register the brand promises.","f":"Either (a) keep it text-forward but warm — replace the tinted glyph tiles with the calm trust-chip row and let the serif header carry the surface — or (b) add a single small warm editorial anchor (e.g. a painterly enamel-pot / saucepan single-subject per §0.1a) above the title, in the ingredient single-subject style. Do NOT add a cold 3D chrome render (banned §0.1b)."},{"c":"parity","s":4,"i":"Web RecipeUpload (src/app/components/RecipeUpload.tsx) diverges from this iOS idle surface on three fronts: (1) NO 'IMPORT FROM' source row at all — the honest trust-chip pattern can't be matched because the grid doesn't exist on web; (2) NO caption-preview/trust path for IG/TT links (gap #2) — web hits the og-scrape directly with no 'We never fetch the post itself' framing; (3) web 'How this fits your day' is a single-line % sentence + a recharts MacroWheel pie (line 2110), while mobile shows a 4-tile 'of {target}' layout. Neither platform yet implements the spec's prescribed thin labelled per-macro bars + verdict line (§3.5), but the platforms also disagree with EACH OTHER.","f":"Per the §5 parity table: bring the caption/trust card to web (gap #2), unify the 'fits your day' presentation across platforms (ideally to the spec's labelled bars + Lifesum verdict line), and decide the source-trust-chip treatment on both. Gate behind recipe-import-redesign flag; ship the visual change on both platforms in the same commit per the cross-platform rule."},{"c":"style","s":2,"i":"Recent-import source badges are hard-coded brand-colour rectangles: recentBadgeTT = solid #000, recentBadgeIG = solid #E4405F (import-shared.tsx). These raw brand hexes are outside the locked palette and read as loud stickers against the warm/plum system. The spec §3.2 wants a neutral mono badge (#F6F5F2 bg, #1B1814 text, #ECEAE4 border, Radius 6).","f":"Replace the solid black / Instagram-pink badges with the spec's neutral mono chip (cream fill, ink text, hairline border, 6px radius) so all four source types (TT/IG/YT/W) share one calm treatment."},{"c":"typography","s":2,"i":"The screen H1 is the brand wordmark 'Sloe' (Newsreader) followed by 'Paste a recipe link' as the serif title. The spec §3.2 prescribes 'Import a recipe' as the Fraunces/Newsreader 22px H1 with 'From any link, social post or website.' as the sub. Leading with the wordmark on a deep sub-screen is redundant (the nav bar already shows 'IMPORT') and the heading hierarchy doesn't match the spec.","f":"Drop the in-card wordmark on this sub-screen, promote 'Import a recipe' to the serif H1 and use the spec sub-copy. Keep the Sloe wordmark for top-level/brand surfaces, not a pushed import screen that already has an 'IMPORT' eyebrow in the top bar."},{"c":"typography","s":2,"i":"Top-bar title 'IMPORT' uses fontWeight 800 with letterSpacing 3 in the clay/plum accent (topTitle). Weight 800 + 3px tracking is heavier/wider than the section-eyebrow ramp (§2.2 wants 10–11px 600 +0.08em). It reads as a shouty all-caps label rather than the calm editorial eyebrow the system uses elsewhere.","f":"Bring the top-bar title to the eyebrow token (11px, weight 600, ~1px tracking, sage or ink) or use a Newsreader title-case label; avoid 800 weight which exists nowhere else in the ramp."},{"c":"functionality","s":2,"i":"The platform inline hint (shown when an IG/TT/YT URL is typed) is styled as a tinted clay box (accent.primary + '12' bg, '33' border) — visually it competes with the primary Import button directly below it and uses the clay accent for an informational note, whereas the system reserves clay for CTAs/active states and uses sage/amber for advisories.","f":"Restyle the inline hint as a calm note: #F6F5F2 fill or a sage left-border per the design-system 'recovery/note' card variant (§6.2), Inter 12px sage text. Keep the share-outline glyph but in sage. This stops two clay elements stacking."}]},{"key":"discover","model":"sonnet","files":["apps/mobile/app/(tabs)/discover.tsx","src/app/components/DiscoverFeed.tsx"],"gaps":[{"c":"typography","s":5,"i":"The recipe-card title 'Classic Greek Salad' renders in Inter sans (discover.tsx line 463: `{ ...Type.body, fontWeight: '700' }` = Inter 14pt). This violates the single most load-bearing typographic rule in the locked design system (§2.3 rule 2: 'Meal names and recipe names ALWAYS Fraunces throughout the product') and recipes.md §3.1 which specifies Fraunces 17pt bold for card titles. A sans recipe name is the clearest tell that this is below the Julienne editorial bar.","f":"Render the hero-card title with the serif face — replace `{ ...Type.body, fontWeight: '700' }` with `Type.headline` (Newsreader serifMedium 17pt) or a dedicated serif title token at ~17–18pt. Apply the same serif to the 'More ideas' row titles (line 576, currently `Type.body`). Verify in a fresh sim capture that Newsreader actually loaded (system serif fallback is a known trap)."},{"c":"typography","s":4,"i":"Section headers 'Recipe ideas' / 'More ideas' / 'My Library' all use `Type.headline` = serif 17pt/22lh. At 17pt they read as weak, almost caption-weight dividers in the capture — they do not carry the editorial section-divider weight the spec wants. Design system §2.2 puts section heroes at display-subtitle (22–28pt) and recipes.md §0 puts section titles at 20–22pt serif `title`. The screen also has no serif H1 on the Discover canvas itself (the 'Recipes' chrome title is separate).","f":"Promote the three section headers to a serif 20–22pt weight (`Type.title` at 24pt is one step too far; introduce/borrow a 20–22pt serif section token, or use `Type.headline` at a bumped size). Give them more presence than a recipe row label so the eye parses 'Recipe ideas' as a section break, not a line of body copy."},{"c":"spacing","s":4,"i":"Multiple off-scale spacing values against the mobile Spacing ladder (xs:4 sm:8 md:16 lg:20 xl:24 xxl:32 xxxl:40). Hero-card vertical gap is `gap: 12` (lines 936, 957) — 12 is NOT a mobile token (it is the *web* md, but the mobile scale jumps 8→16). Hero card body padding `padding: 14` (line 452), import-CTA `padding: 14` + `gap: 12` (lines 819-826), search bar `paddingHorizontal/Vertical: 14` (lines 617-618), pills `paddingHorizontal: 13` (lines 678/711), 'More ideas' rows `gap: 12, padding: 12` (lines 552-553). The screen is built almost entirely on 12/13/14 — none of which are on the mobile scale.","f":"Snap every value to the mobile Spacing scale: card gap 12→16 (Spacing.md); card/CTA/search padding 14→16 (Spacing.md); 'More ideas' row padding 12→16; pill paddingHorizontal 13→12 or define a deliberate chip token (note theme.ts comment claims 13/8 is 'canonical' for descender clearance — if kept, document it as an intentional chip carve-out per no-silent-deferrals, otherwise it reads as drift). The 12px values are likely web tokens leaking into mobile."},{"c":"parity","s":4,"i":"Web DiscoverFeed.tsx has structurally diverged from this iOS surface. (1) Web renders a `<h1>Discover</h1>` (sans extrabold 24px, line 420) — mobile has NO 'Discover' H1; it uses RecipesTabChrome with a serif 'Recipes' title + Library/Discover sub-tabs. Different IA. (2) Web section headers 'Recipe ideas'/'More ideas' are caps eyebrow labels (`text-[13px] font-extrabold uppercase tracking-[0.04em] text-muted-foreground`, lines 847/940) — mobile renders them as 17pt serif headlines. Two different treatments for the same header. (3) Web hero cards use full-bleed image with WHITE OVERLAY title text + drop-shadow (lines 883, 653); mobile uses below-image cream card with ink title (the 2026-05-22 'everything should be like the bottom one' consolidation). Web never adopted that consolidation.","f":"Reconcile the two surfaces (memory rule: mobile design decisions apply to web in the same commit). Decide one canonical pattern per element — almost certainly: drop the web overlay-title hero in favour of the below-image cream card to match mobile's consolidated grammar; align section-header treatment (pick serif headline OR caps eyebrow on BOTH); and reconcile the 'Discover' H1 vs 'Recipes' chrome-title IA. Gate behind a flag per the visual-change rule."},{"c":"style","s":3,"i":"The category pill row in the capture shows 'Following · All · Trending · Quick 30 · Under 500 cal'. Selected pill is a soft aubergine tint (treatment §7), which is correct, but in the capture 'All' reads as the only selected pill while the others are transparent with a hairline border — the inactive pills sit on a fully transparent background so they read as slightly floating/unanchored against the white page, and the row's relationship to the search field above and 'Recipe ideas' below is loose. Pill labels also use `Type.caption` (11pt) which is light for a primary filter control.","f":"Tighten the filter row's vertical rhythm to the section above/below (consistent Spacing.md), and consider bumping pill label to `Type.label`/13pt for a more deliberate control. Confirm the inactive pill border colour (`colors.cardBorder`) is visible enough on white to read as a pill, not a ghost."},{"c":"style","s":2,"i":"The hero macro row renders '380 kcal · 13g · 18g · 28g · 5g' with icon glyphs. The macro letters/units are present but the row is dense and every value reads at near-equal weight despite `emphasiseProtein` being passed — in the capture the protein emphasis (heavier ink on 13g) is subtle and easy to miss. recipes.md §3.1 wants protein to be the one clear visual accent ('this is a tracker, not just a recipe app').","f":"Strengthen the protein emphasis so it is unmistakably the accented value — e.g. heavier weight + full ink + slightly larger icon/dot, per MacroIconRow's `emphasiseProtein` contract. Verify the difference is legible at card scale in a capture, not just in code."},{"c":"functionality","s":2,"i":"The import CTA copy reads 'Import from TikTok, Instagram...' with the trailing ellipsis truncating mid-sentence by design (line 833), and the subtitle 'Paste a link or share from any app'. The truncated brand list reads slightly unfinished/placeholder-ish rather than intentional. Functionally the CTA is correctly wired (routes to /import-shared, testID present) — this is a polish nit, not a break.","f":"Either complete the brand list ('TikTok, Instagram & YouTube') or rephrase to avoid the dangling ellipsis ('Import from a link or social post'). Keep the testID and route unchanged."},{"c":"photography","s":1,"i":"Photography is on-spec and a genuine strength: the Greek Salad hero is a real editorial-style finished-dish photo (overhead plated salad, warm tones), matching imagery system §11.2. No cold/empty/placeholder tiles are visible in this capture. The only forward risk is the below-fold cards and the warm RecipeHeroFallback path, which are wired correctly (sage→cream fallback per §11.4) but not exercised by this populated capture.","f":"No fix needed for the visible hero. Confirm in a multi-card capture (and an image-less recipe) that the RecipeHeroFallback tile renders the warm sage→cream treatment and never the pale-lilac border base, per the 2026-06-08 conformance note in recipes.md."}]},{"key":"library","model":"sonnet","files":["apps/mobile/app/(tabs)/library.tsx","src/app/components/Library.tsx"],"gaps":[{"c":"functionality","s":5,"i":"STALE CAPTURE — the rendered card does not match HEAD. The PNG shows a 2-line macro block (line 1 '312 kcal · 55g protein', line 2 '4g · 8g', then '4 servings') with an OLD icon set (flame / meat-drumstick / fork-knife / wheat). HEAD's working tree (uncommitted: library.tsx +93, MacroIconRow.tsx +16) renders a SINGLE wrapping MacroIconRow with showMacroLetters=false, emphasiseProtein (heavier ink protein), Dumbbell protein icon, plus a separate '★ saves · N min' meta row that falls back to servings. The dev client was not reloaded against the working tree, so every card-level finding from this pixel is unverifiable. This is the documented stale-dev-client-bundle trap.","f":"Reload the dev client against the current working tree (terminate + relaunch — Fast Refresh is not enough after StyleSheet/module changes) and re-capture library.png before drawing any card-level conclusions; the harness should hard-fail when bundle != HEAD (ENG-769). Re-audit the card from the fresh capture."},{"c":"photography","s":4,"i":"Bottom-right card is a COLD empty cream tile — a faint sage fork/spoon RecipeHeroFallback glyph on flat cream, with a bookmark dot but no title/photo above the fold. Next to two warm editorial dish photos it reads as a broken/loading card, not an intentional fallback. §11.4 wants sage→cream gradient + cuisine glyph, but at this size on a near-empty account it still undersells vs Julienne's all-photo gallery.","f":"Confirm RecipeHeroFallback renders the sage→cream GRADIENT (not flat cream) at card size and the cuisine glyph is sized/centred to read as deliberate. For seed/curated recipes ensure a real FLUX editorial photo is generated so the gallery is photo-dense; reserve the fallback for genuinely image-less user imports."},{"c":"spacing","s":3,"i":"Off-scale paddings throughout the header chrome. filterPill: paddingHorizontal 13, borderRadius 20 (both off the Spacing 4/8/16/20/24 and Radius 4/6/8/12 ladders). searchInputWrap: gap 10, paddingHorizontal 14, paddingVertical 14 (10 and 14 off-scale). quietControl: paddingHorizontal 10, paddingVertical 5 (10 and 5 off-scale). planImportPill: paddingHorizontal 11, paddingVertical 6 (11 off-scale).","f":"Snap to the canonical scale: filterPill -> paddingHorizontal 12, radius Radius.full; searchInputWrap -> gap 8, padding 16 (Spacing.md), radius 12; quietControl -> paddingHorizontal 8, paddingVertical 4; planImportPill -> paddingHorizontal 12, paddingVertical 4. Re-derive these on-scale instead of carrying the 13/14/11/5/20 magic numbers left by historical tester fixes."},{"c":"typography","s":2,"i":"Fractional / off-ramp font sizes on the card. macroValue fontSize 11.5 (no 11.5 in the ramp; caption is 11-12); MacroIconRow Chunk hardcodes fontSize 12 inline. Card title is Newsreader_500Medium 15pt — recipes.md §0 'title' role and the cross-cutting DS §2 treat recipe names as an editorial moment, so 500/15 sits at the light end and slightly undersells the editorial register vs Julienne.","f":"Replace 11.5 with a ramp token (12pt caption) and route Chunk's inline 12 through the same caption token. Consider bumping the card title to Newsreader/Fraunces 600 at 15-16pt for more editorial weight while keeping the 2-line clamp."},{"c":"parity","s":3,"i":"Web and iOS Library cards have diverged. iOS uses the shared MacroIconRow (icon+value chunks, single wrapping row). Web mobile-grid hand-rolls its own macro span row (raw 11.5px text, gap-x-2/gap-y-0.5) instead of the RN gap:10 rhythm. Web DESKTOP grid is an entirely different card (4:3 hero, kind badge Saved/Your recipe/Imported, kcal-pill overlay, fit-% pill, 'Create your own version' button) with NO iOS equivalent — iOS has no fit-% pill and no kind badge.","f":"Pick one canonical mobile card and make web's mobile-grid consume the same macro primitive (port MacroIconRow or a shared macro-chip-row to web) so gap/size/weight match. Reconcile the desktop-only fit-% pill + kind badge + 'Create your own version' against iOS — add to iOS or document as an explicit desktop carve-out; today it is silent drift."},{"c":"functionality","s":2,"i":"Header reads 'Recipes' (section chrome) with Library/Discover sub-tabs, but recipes.md §3.1 IA specifies a possessive 'Your Recipes' editorial header for Library ('this is your collection, not a database'). The personal-possessive premium framing is absent; the surface reads as a generic section, not a personal cookbook.","f":"Either adopt 'Your Recipes' for the Library tab title, or explicitly reconcile recipes.md §3.1 with the deliberate RecipesTabChrome constant-'Recipes' decision so it stops reading as an unmet requirement."},{"c":"functionality","s":2,"i":"Sort is a blind CYCLE. The count-line 'Recent' chip cycles Recent->Calories->Protein on each tap with no menu — recipes.md §2.1 flags this exact weakness and §3.1 calls for a 'Sort: {label}' chip opening a 3-option action sheet. The chip shows the current label (good) but tapping silently re-cycles, so reaching 'Protein' from 'Recent' requires guessing the order.","f":"Replace cycleSort with an action-sheet picker (Recent / Most calories / Most protein) per §3.1, keeping the current-sort label on the chip. Mirror on web (cycleSort) for parity."},{"c":"spacing","s":2,"i":"Card body vertical rhythm is uneven: cardBody gap 4 plus per-child overrides macroRow marginTop 2 and metaRow marginTop 4, so title->macro->meta spacing stacks inconsistently rather than on one rhythm.","f":"Use a single consistent vertical gap on cardBody (gap: Spacing.xs = 4) and drop the marginTop 2/4 child overrides so title, macro row, and meta row sit on a uniform 4pt rhythm; verify in a fresh capture."},{"c":"style","s":2,"i":"Category pills, count-line quiet controls, and the search field all share a near-identical cream/transparent + hairline treatment, so the filter row reads flat / low-hierarchy on white. The selected pill's soft aubergine tint fill + aubergine ink (Sloe §7) is calm but low-contrast at small size and easy to miss vs Julienne's clearer active filter.","f":"Verify the active category pill's aubergine-soft fill clears 3:1 on white and reads distinctly from inactive pills in a fresh capture; if subtle, give the active pill a primarySolid hairline border so the current filter is unmistakable."},{"c":"style","s":1,"i":"Library auto-redirects to Discover at savedCount=0 (useFocusEffect router.replace), so on a near-empty account the polished dashed-cream emptySlab (frost-mist badge, serif heading, stacked CTAs) is effectively unreachable in the default flow — the only first impression is Discover, and the empty-state polish is invisible.","f":"Confirm ENG-100 redirect is still intended; if so, document the emptySlab as a fallback-only state (deep-link/cold-open edge) or prune the redundant branch so the polish effort isn't dead code."}]},{"key":"progress","model":"sonnet","files":["apps/mobile/app/(tabs)/progress.tsx"],"gaps":[{"c":"functionality","s":5,"i":"Contradictory data on AVERAGE ADHERENCE: headline reads 109% calorie adherence but all 7 on-target streak dots top-right render empty/grey. On-target = calories>0 AND calories<=effectiveTarget; a 109% AVERAGE adherence with zero on-target days is internally inconsistent and reads as broken/placeholder chrome on this account. The dots compute from weekStats.days (this-week, calendar) while the % is range-scoped (30d) — two different windows shown as one story.","f":"Either source the streak dots from the SAME range window as the headline % (use macroRange/caloriesRange per-day booleans, not weekStats.days), or suppress the dot row entirely when onTargetDays.filter(Boolean).length === 0 (mirror the ProgressOnTargetRibbon's 'don't show an empty achievement' rule). Empty grey dots next to a 109% headline is the single most premium-damaging thing on the surface."},{"c":"style","s":4,"i":"ProgressStoryGate ring (THIS WEEK card, top-right) is nearly invisible — at 0/3 logged the 24pt single-stroke arc shows only a faint grey track with no clay fill, so it reads as an empty/dead circle rather than a progress affordance. Against editorial-luxury (Julienne) this is a cold, unexplained dot.","f":"Give the ring a minimum visible clay arc floor (e.g. clamp ringFraction to >=0.06 so even 0/3 shows a small clay tick), or replace the bare ring at 0 days with the explicit '0 / 3' numeral inside the ring (the spec §3.2 wants 'days until your first story' under the ring). Right now the ringLabel '0 / 3 days logged · 3 needed to unlock' is below the headline but the ring itself communicates nothing."},{"c":"functionality","s":4,"i":"Above-fold weight chart (54.6 kg + Trend/Scale) is context-free in the first viewport: bare clay polyline with no Y-axis ticks, no visible goal-line label, no stat-pair delta beside the big kg numeral. The spec §3.4/§7.1 mandates a stat-pair header (avg + signed delta toward/away from goal) and a pinned 'GOAL {value}' pill. The 'Goal {value} · on track for ~{date}' line and START/CURRENT/GOAL/RATE row exist but sit below the chart, off the first screen. MacroFactor/Zero parity bar wants the interpretation ABOVE the line.","f":"Surface the week-delta (↓ −0.6 kg this week) inline beside the 54.6 kg numeral (the code already computes weekDeltaKg and renders the TrendingDown row — confirm it shows; on this empty-ish account it's suppressed by the 0.05 threshold). Add the dashed goal-line label pill on the sparkline (currently a label-less dashed line at t.sub 0.5 opacity — invisible). Add 2 quiet Y-axis end-labels (min/max kg) so the line has scale."},{"c":"spacing","s":3,"i":"Pervasive off-scale internal spacing against the canonical mobile Spacing token (xs:4 sm:8 md:16 lg:20 xl:24 — note 12 and 6 and 14 are NOT on the scale). Concrete offenders: range-picker gap:6 (→8) and skeleton gap:6; weight-card header gap:12, sparkline marginTop:12, stat-row marginTop:12/paddingTop:12, log-button marginTop:14, view-all marginTop:10; daily-calories legend marginTop:12; AVERAGE ADHERENCE streak-dots gap:6; ProgressStoryGate eyebrow marginBottom:6; energy-triad value marginTop:6. These read as a hand-tuned cascade, not a system — exactly the cadence inconsistency the spec flags.","f":"Snap every raw 6→Spacing.sm(8), 12→Spacing.md(16) or sm(8) where 16 is too loose, 14→Spacing.md(16), 10→Spacing.sm(8). The ProgressAverageAdherence card already did this snap under ENG-996 (Spacing.sm/lg/md) — extend the same discipline to the weight card, range picker gap, energy triad, daily-calories, and StoryGate. The 6px gaps in particular read visibly tight."},{"c":"spacing","s":2,"i":"Range-picker pill gap (6px) is tighter than the card-to-card rhythm (Spacing.lg=20 via progressScrollStyle.gap) and tighter than the 8px the pills want, making the 7d/30d/90d/All row feel cramped relative to the airy cards below it. The pills also use Radius.full with paddingVertical:8 only — a slightly thin tap target visually for a luxury surface.","f":"gap: Spacing.sm (8); bump pill paddingVertical to 9–10 so the pills have more presence and the active 30d soft-tint fill reads as a deliberate selected state, not a hairline."},{"c":"style","s":2,"i":"AVERAGE ADHERENCE macro bars are full-width, 8pt-tall, fully-saturated fills (Protein sage 79%, Carbs clay 104%, Fat amber 117%, Fibre teal 34%). Four heavy saturated bars stacked read busier/more 'tracker-dashboard' than editorial-luxury. The over-budget Carbs/Fat correctly go to amber with '· over', but Carbs at 104% is rendered in the macro clay AND flips to amber on over — visually Carbs (clay) and the over-amber are close in hue, muddying the over-signal.","f":"Consider a lighter bar track-to-fill contrast (the fill is fine but 8pt full-saturation x4 is heavy) or reduce bar height to 6pt per spec §7.3 (4–6pt). For the over-signal, the spec §7.3 wants an amber '!' icon + clamp-at-100 with a 3-dot overflow indicator rather than recolouring the whole bar amber — the current full-amber bar loses the macro identity. Lower priority since the · over text + colour is a legible system."},{"c":"typography","s":2,"i":"Big numerals correctly use Newsreader serif (Type.display: 109%, 54.6 kg, 24pt daily-avg) — on-bar. But the THIS WEEK headline 'Your story builds with your data' uses Type.headline (Newsreader 17pt/500) while the spec §3.2 calls the headline the most-important text at Fraunces 18pt. Minor: 17pt vs 18pt is within tolerance, but the StoryGate body is Inter 12pt/18 (styles.body) — 12pt is below the spec's 13–14pt body floor and reads small/secondary under the serif headline.","f":"Bump StoryGate body from fontSize:12 to 13 (label-secondary floor) for legibility parity with the AVERAGE ADHERENCE rows (13pt). Headline 17→18 optional. Confirm Newsreader actually loaded in the capture (it did — the serif numerals render), so no fallback-Georgia risk here."},{"c":"photography","s":1,"i":"No agreed Sloe photography (FLUX editorial / ingredient single-subjects) anywhere on this surface — which is CORRECT for Progress (it is a data/story surface, not a recipe surface). The empty-state 'Your progress will appear here' uses a BarChart3 lucide glyph in an IconBox, and the on-target ribbon uses an Award medal glyph — both line-icon, on-system. No cold/placeholder imagery. Flagging only to confirm: this is not a gap, it is the correct absence per design-system §11 (Progress is not a photography surface).","f":"No action — confirm reviewers don't 'add a hero image' to Progress. The line-icon empty state is the right editorial-restraint call. (Included for completeness of the photography lens.)"},{"c":"parity","s":3,"i":"Web mirror divergence risk: the StoryGate ring track on web uses className='text-border' (currentColor) while mobile uses colors.cardBorder — visually equivalent, fine. BUT the web ProgressStoryGate has the same near-invisible-ring-at-0 problem AND the web mirror layout (ProgressDashboard.tsx is 117KB / ~2.6k lines) is far larger than the mobile screen file — high risk that web has additional cards or a different above-fold order than the mobile Sloe 492:2 sequence (range → THIS WEEK → AVERAGE ADHERENCE → weight → triad → daily-calories → ribbon). The streak-dot data-window inconsistency (range-% vs week-dots) will reproduce identically on web since both consume the same props shape.","f":"When fixing the on-target-dots window bug and the ring-visibility floor, apply the SAME fix to web (src/app/components/suppr/progress-story-gate.tsx + progress-average-adherence.tsx) in the same commit per the mobile-decisions-apply-to-web rule. Audit ProgressDashboard.tsx above-fold card order against the mobile 492:2 sequence to confirm no divergence — the 117KB file is over the 400-line ceiling and a likely drift vector."},{"c":"style","s":2,"i":"Card elevation: cards use CARD_RADIUS=24 (radius-xl, generous and on-brand) with cardElevation hairline+soft-shadow — clean and premium. The THIS WEEK lilac-wash card (rgba(106,75,122,0.12) bg + 0.16 border) sits at Radius.lg(20) via styles.card, a 4px radius MISMATCH with its sibling cards at radius 24. Small but on a luxury surface the corner-radius inconsistency between the lilac insight card and the cream cards below it is detectable.","f":"Set ProgressStoryGate/ProgressHeadline card borderRadius to CARD_RADIUS (24) to match the AVERAGE ADHERENCE / weight / daily-calories cards, so all stacked cards share one corner radius."},{"c":"functionality","s":2,"i":"The AVERAGE ADHERENCE 'up N%' week-over-week trend chip is permanently hidden (adherenceDeltaPct is never passed by the host — documented data gap until weekly aggregates persist). This is correctly handled as 'never fabricate', but it means the top-right of the card on a real account shows ONLY the streak dots, leaving the headline % without the trend context the spec wants. Not broken, but an incomplete-feeling card vs the Figma intent.","f":"No invented data (correct). Track the weekly-aggregate persistence as the unblock (per no-silent-deferrals: this should have a Linear ID in the comment). Once the delta stream lands, wire adherenceDeltaPct so the chip fills the intended top-right slot and the streak dots aren't alone."}]},{"key":"create-recipe","model":"sonnet","files":["apps/mobile/components/recipe/CreateRecipeWizard.tsx","apps/mobile/tests/unit/createRecipeWizard.test.ts"],"gaps":[{"c":"typography","s":5,"i":"The screen H1 'What are you making?' renders in Inter sans (raw fontSize:22, fontWeight:700 via styles.sectionTitle, line 725-730). The design system locks serif (Fraunces/Newsreader) for screen H1 + onboarding step questions at display-title 32-40pt (_design-system.md §2.2/§2.3 rule 1, recipes.md §0 'display' role 28-32pt serif). This is a 5-step guided creator — the step question is the editorial moment of every step and it is the single most impactful serif miss across the surface.","f":"Set sectionTitle to FontFamily.serifSemibold (Newsreader), ~28pt, lineHeight ~32, via Type.display (or a serif variant). Apply to all five step questions ('What's in it?', 'How do you make it?', 'Macros look right?', 'Save your recipe')."},{"c":"typography","s":5,"i":"The entire wizard bypasses the canonical Type ramp and FontFamily tokens — every text node uses inline raw fontSize/fontWeight (sectionTitle 22/700, sectionSub 14, label 12/700, servingsValue 24/700, ingName 14/600, etc.). Nothing imports Type or FontFamily. _design-system.md §2.3 rule 4 ('no hardcoded font sizes — use the scale tokens') and rule 3 ('big numerals always serif') are both violated. This is why the screen reads as a stock form, not Sloe.","f":"Import { Type, FontFamily } from '@/constants/theme' and map: H1→serif display, sub→Type.bodyMuted, label→Type.label, servings value→Type.heroValue (serif) with tabular-nums, ingredient name→Type.body. Remove the bespoke inline sizes."},{"c":"photography","s":4,"i":"The 'Add photo (optional)' tile is a cold dashed-border empty box with a grey line-icon camera and uppercase tertiary label (styles.photoFallback, lines 758-770; rendered 1032-1037). _design-system.md §0.1 explicitly says the camera 'Photo' surface MAY be a warm stylised-photoreal image in the ingredient-single-subject style, and §6.3/§11.4 ban cold/grey empty chrome — empty states should read warm, never like a loading or disabled state. This is the hero area of step 1 and it currently reads cold and cheap.","f":"Replace the dashed grey box with a warm fallback: either the brand camera/object image (same FLUX pipeline as ingredients) on a #F6F5F2 fill, or a sage→cream gradient tile with the camera glyph in sage #7C8466 — matching the RecipeHeroFallback treatment already shipped on Library cards (recipes.md §11.4). Drop the dashed border."},{"c":"functionality","s":4,"i":"The servings stepper is a bare −/value/+ row (styles.servingsRow + circular servingsBtn, lines 771-794), exactly the 'looks like a form field, not a deliberate stepper' weakness the spec calls out (recipes.md §2.2 + §3.2 'Servings stepper boxed, new'). The value '4' sits unboxed and in sans, so the control reads as raw text between two pills.","f":"Wrap the count in a boxed #F6F5F2 container (hairline border, 8pt radius, ~32-40pt) per recipes.md §3.2, and render the numeral in serif Type.heroValue with tabular-nums. accessibilityRole='adjustable' + accessibilityValue so VoiceOver reads it as a stepper."},{"c":"spacing","s":3,"i":"Input vertical padding is off-scale: paddingVertical:14 on styles.input (line 743) and macroFieldInput padding:10 (line 897), stepInput uses Spacing.md (16). The canonical Spacing scale (theme.ts) has no 14 or 10 — values must be xs4/sm8/md16/lg20/xl24. 14 and 10 are bespoke one-offs that break the 4pt grid and make field heights inconsistent across steps.","f":"Set input paddingVertical to Spacing.md (16) or sm (8)*; macroFieldInput padding to Spacing.sm (8); audit all numeric paddings in the StyleSheet (also primaryBtn paddingVertical:16=Spacing.md OK, secondaryBtn 14→16, backHit padding:6→Spacing.xs*2 or hitSlop only)."},{"c":"spacing","s":2,"i":"The progress-bar segment gap is a raw 4 (styles.progressRow gap:4, line 703) and progressDot height is a raw 4 with radius 2 — fine on the grid (xs) but hardcoded as literals rather than Spacing.xs, and the row uses paddingHorizontal:Spacing.xl (24) while the scroll body also uses Spacing.xl, so the progress track and content share an edge that the capture shows slightly tight against the 'What are you making?' block (progress→H1 gap is only Spacing.md 16 via scroll padding). The eyebrow→progress→title rhythm is cramped vs the airy Figma.","f":"Use Spacing.xs for the segment gap explicitly; add ~Spacing.xl (24) breathing room between the progress row and the first section block (the system's '2xl above section eyebrow' rhythm, §3.1)."},{"c":"typography","s":2,"i":"The 'NEW RECIPE' eyebrow uses letterSpacing:2 at fontSize:11 (styles.topTitle, lines 688-693) ≈ 0.18em — more than double the system eyebrow tracking of +0.08em (Type.label = 0.88 at 11pt; _design-system.md §2.2 section-eyebrow). It reads as over-tracked vs every other eyebrow in the app.","f":"Use Type.label (letterSpacing 0.88) or set letterSpacing to ~0.88 (0.08em) for parity with the rest of the product's ALL-CAPS eyebrows."},{"c":"style","s":3,"i":"The Continue CTA is a transparent plum outline (styles.primaryBtn, lines 928-938). On cold open of step 1 the title is empty so advanceEnabled is false and the button drops to opacity 0.45 (line 1359), which the capture shows as a faint grey ghost button with near-invisible label. An outline-only disabled CTA at 45% reads as broken/dead on first impression rather than 'fill in the field above'. Premium creators (Julienne, Crouton) keep the primary visible and let the field validation guide.","f":"Either (a) keep the outline visible and add an inline helper ('Add a name to continue') instead of dimming to 0.45, or (b) raise the disabled opacity floor to ~0.6 and keep the border at full strength so it reads as 'not yet', not 'dead'. Consider the filled plum slab for this single conversion-adjacent CTA given the outline reads weak when disabled."},{"c":"style","s":3,"i":"Input fill uses cardElevation.liftBg ?? colors.card (#F6F5F2) on a #FFFFFF page with the soft cardSoft shadow now default (theme.ts Elevation.cardSoft). In the capture the recipe-name field and photo box read as flat #F6F5F2 rectangles with no perceptible lift — the same 'cards blending into the background' problem Grace flagged (theme.ts cardSoft comment). The field and photo tile are barely separated from the page.","f":"Verify cardElevation.shadowStyle is actually applied to styles.input (it is NOT — only photoFallback/ingCard/stepRow/totalsCard/saveCard spread shadowStyle; the text input does not). Add the soft lift to the input + ensure the photo tile lift renders on-device, or give inputs a hairline #E8E2EC border so they read as deliberate fields."},{"c":"style","s":2,"i":"The character counter '0/80' (lines 1051-1055) renders in textTertiary 11pt right-aligned and is always visible even at 0 chars. A persistent '0/80' on a pristine field is low-polish noise — premium forms reveal the counter only as the limit approaches (e.g. last 20 chars).","f":"Show the counter only when title.length > TITLE_MAX_LENGTH - 20 (or hide at 0). Keep it textTertiary but make it conditional so the cold-open screen is cleaner."},{"c":"functionality","s":2,"i":"Step 1 collects only name + photo + servings, but there is no description field anywhere in the wizard (description is hardcoded null on save, line 558) — yet the Recipe Detail spec (recipes.md §3.2) renders a 'Description card'. A recipe created via the wizard can never have a description, so the detail surface's description card is permanently empty for wizard-created recipes. This is a quiet feature gap, not visible in the capture but confirmed in code.","f":"Either add an optional description field (step 1 or 3) or explicitly document description-on-wizard as out-of-scope with a Linear ref in the save handler (no-silent-deferrals rule). Currently `description: null` is unannotated."},{"c":"parity","s":3,"i":"The web mirror (src/app/components/RecipeUpload.tsx, 2320 lines) is a single-screen form, not a 5-step wizard — this is a DOCUMENTED carve-out (CreateRecipeWizard.tsx header + recipes.md §4: 'wizard pacing wouldn't help on desktop'), so the step PACING divergence is intentional, not drift. But the per-step VISUAL treatment must still match the shared system, and it doesn't: web uses serif plum headings + var(--radius-card-lg) + shadow-lg cards (RecipeUpload lines 1417-1496), while the iOS wizard uses sans inline type + Radius.md(6) inputs + mostly flat fills. The two surfaces will look like different products on the same step content.","f":"Bring the iOS wizard onto the same serif headings + card-lg radius + soft-lift treatment the web form already uses, so name/photo/servings/macros read identically cross-platform even though the navigation model differs. Track as the parity action under recipes.md §4 'boxed servings stepper' + 'verb row' rows."},{"c":"style","s":2,"i":"Radius mismatch vs spec on this surface: recipes.md §0 locks cards at 12pt and inputs/images at 8/12pt, but the wizard inputs use Radius.md which is now 6pt (theme.ts Radius lock 2026-05-22) and the photo tile uses Radius.lg=8. So fields are tighter-cornered (6pt) than the 12pt the recipes spec calls for. The 2026-05-22 radius tightening (8/6/4/12) post-dates the recipes spec, so there's a genuine token-vs-spec conflict — but per _design-system.md §0 the system file/theme wins; either way the inputs at 6pt read sharper/more clinical than the warm 12pt the surface intends.","f":"Reconcile: if 12pt is the intended warm radius for recipe inputs/cards, use Radius.xl (12) on input/photo/ingCard; if the 6pt system lock is canonical, update recipes.md §0 to 6/8/12 so the spec stops claiming 12pt cards. Don't leave the conflict unresolved."},{"c":"functionality","s":5,"i":"RENDERING BUG: the sticky 'Save Recipe' footer overlaps and sits ON TOP of the live INGREDIENTS section header, its helper text, and the Paste list / Scan photo quick buttons (visible in capture — footer rule + 'Save Recipe' label cut through the grey helper copy). The ScrollView contentContainer uses paddingBottom: 120 but the footer is absolutely positioned with safe-area + Spacing.md padding, so on shorter content the footer floats over interactive form rows instead of below a reserved gutter. This is a tappable-content occlusion bug, not just a cosmetic one.","f":"Measure the footer height (onLayout) and set ScrollView contentContainerStyle.paddingBottom to footerHeight + insets.bottom + Spacing.xl, or render the footer inside the KeyboardAvoidingView flow below the ScrollView (flex layout) so it can never overlap scrollable rows. Verify in sim that the Ingredients header + quick-add row clear the footer when the form is short."},{"c":"typography","s":5,"i":"No serif anywhere on the screen. The design system mandates Fraunces/Newsreader for screen titles and editorial moments (§2.3 rule 1; recipes.md display role 28–32pt). The header reads 'New recipe' in 13pt Inter 800 with letterSpacing:3 ALL-the-way-tracked — that is a caption/eyebrow treatment masquerading as a title, the single biggest reason this screen reads as a generic settings form rather than an editorial cookbook. Web mirror already renders a real serif H1 (font-[family-name:var(--font-headline)] text-3xl).","f":"Replace the tracked-Inter top title with a Fraunces display title. Either a left-aligned 28pt Fraunces 'New recipe' below the Cancel bar (matching web's text-3xl H1) or a centred Fraunces 17–20pt nav title. Load Fraunces via expo-font and verify the glyphs render in a sim capture before push (system serif fallback otherwise)."},{"c":"photography","s":4,"i":"The cover image control is a cold empty grey/cream dashed box with a generic camera outline + 'ADD PHOTO' eyebrow. §11.4 forbids a neutral grey placeholder and the recipes spec calls for a warm cream gradient (#F6F5F2→#ECEAE4) with a sage pan/pot glyph, never a neutral tile. It currently reads as an unstyled file-upload affordance. Worse, there is a hard parity break: the web mirror seeds a real DEFAULT_COVER_IMAGE (Unsplash food photo) so the web form looks finished while mobile looks empty.","f":"Replace the dashed grey placeholder with the warm RecipeHeroFallback tile (sage→cream gradient + sage cookware glyph per §11.4), same component the Library/Discover cards now use. Use a tangible warm camera object per §0.1(a) for the 'Add photo' affordance rather than a flat line camera if a hero-photo CTA is wanted. Decide and align the cover-seed behaviour across platforms (either both seed a placeholder hero or neither)."},{"c":"spacing","s":4,"i":"Input fields use Radius.md = 6pt corner radius. The recipes spec and design-system §4 want 12pt (radius-xl on mobile maps to 12) for input fields / standard cards. 6pt reads boxy and cheap against the rounded Julienne language. The image placeholder uses Radius.lg = 8pt (spec wants 12–16pt outer card clip). Every surface on this form is under-rounded.","f":"Move text inputs, the paste textarea, the publish row, and meal-type chips to Radius.xl (12pt). Move the image tile to 12–16pt. Audit the create-recipe StyleSheet for every Radius.md usage and bump to the spec radius."},{"c":"spacing","s":3,"i":"Pervasive off-scale padding. Inputs use paddingVertical: 14 (not on the 4/8/16/20 scale). addBtn uses paddingVertical: 14. Quick buttons use paddingVertical: 10 + paddingHorizontal: 12. MealTypePicker chips use paddingHorizontal: 12, paddingVertical: 8, gap: 4 hardcoded, and the chip label section eyebrow is fontSize 11 with letterSpacing 1 (the form label uses letterSpacing 1 too — inconsistent with the system +0.08em eyebrow spec). 12 and 14 and 10 are all off the canonical Spacing set (xs:4 sm:8 md:16 lg:20 xl:24).","f":"Snap every padding to the Spacing scale: inputs paddingVertical Spacing.md(16); quick buttons + meal chips paddingHorizontal Spacing.md(16) / paddingVertical Spacing.sm(8); replace hardcoded gap:4 with Spacing.xs. Inputs should clear the 44pt min touch target (16pt vertical padding + 16pt text ≈ 48pt — currently borderline)."},{"c":"style","s":3,"i":"Section labels are all rendered identically as 11–12pt Inter 700 uppercase letterSpacing:1 in textTertiary — RECIPE NAME, DESCRIPTION, SERVINGS, MEAL TYPE, INGREDIENTS all read at one flat weight with no editorial hierarchy. The design system wants section eyebrows in sage (--secondary) at +0.08em tracking with 24pt above / 8pt below rhythm (§2.2 rule 6, §10.11). Tertiary grey is lower-contrast than the sage spec and the uniform treatment gives the form no scannable structure.","f":"Standardise on the section-eyebrow token: Inter 10–11pt 600, letterSpacing ~+0.08em, colour --secondary (sage #7C8466 / accent-aware), Spacing.xxl(32) above each section and Spacing.sm(8) below. This gives the editorial section rhythm the rest of the redesign uses."},{"c":"style","s":3,"i":"The primary 'Save Recipe' CTA is an aubergine OUTLINE (transparent fill, 1.5px border, ink label) per the in-file treatment note. On the final submit of a creation flow this reads as a secondary/ghost action — it lacks the weight of a primary commit and competes weakly with the dark sticky-footer pattern used on Recipe Detail ('Log all' is a filled #1B1814 bar). The form's most important action looks like a tertiary button.","f":"Promote the submit to a filled primary (Clay/Damson per accent rules) or a dark #1B1814 filled bar matching the Recipe Detail sticky footer, 48–52pt height, Fraunces 15pt label per §10.4/spec. Keep the outline treatment only for genuinely secondary actions. Gate behind the surface redesign flag."},{"c":"parity","s":3,"i":"Source-entry model diverges hard between platforms. Mobile is a single scrolling form with Paste list / Scan photo / Scan barcode + voice/photo sheets and a Publish switch. Web RecipeUpload is a create/import dual-mode component with a different richer entry flow (import queue drawer, GoPublicDialog attestation, USDA hit pickers, structured ingredient rows). The recipes spec §3.5 wants a 4-tile serif source picker (link/video/photo/manual) on BOTH; neither matches it, and mobile lacks the GoPublicDialog attestation UI (it uses a one-shot Alert instead of the web checkbox dialog).","f":"Align both to the §3.5 4-tile source picker and converge the publish-attestation UX (ENG-700 convergence). At minimum, document the divergence as an intentional carve-out with a Linear ID rather than leaving two unrelated implementations; do not leave the mobile Alert-attestation vs web dialog-attestation gap unticketed."},{"c":"style","s":2,"i":"The quick-add row (Paste list / Scan photo / Scan barcode) uses three identical low-emphasis hairline pills with Ionicons line glyphs — there is no visual signal that 'Scan photo' is the magic/viral path. The recipes spec (§2.6, §3.5) flags exactly this: source options as a 'plain action sheet — no visual affordance for which sources work best.' Visually these three buttons read as a generic toolbar.","f":"Differentiate the primary import affordance (Scan photo / paste from clipboard) per §3.5 — e.g. a full-width terracotta/clay clipboard quick-action when a URL/list is detected, and lift the photo path visually. Use the warm tangible camera object for the photo tile per §0.1."},{"c":"style","s":2,"i":"Ionicons are used throughout (camera-outline, clipboard-outline, scan-outline, barcode-outline, cafe/sunny/restaurant for meal types, checkmark-circle, close-circle). The design system standardises on lucide line icons for abstract controls (§0.1(b)) and the rest of the redesigned surfaces use lucide-react-native. Mixing Ionicons here is an inconsistency that subtly cheapens the surface and diverges from the icon set used on Library/Detail.","f":"Swap Ionicons for the lucide-react-native equivalents used elsewhere (Camera, ClipboardList, ScanLine, Barcode, Coffee/Sun/UtensilsCrossed, CheckCircle, XCircle) so the whole product shares one icon family. Cross-reference the meal-slot icons against the Library card set."},{"c":"typography","s":2,"i":"Meal-type chips and recipe-name placeholder are fine on legibility but the 'Per serving' totals card renders values in Inter 800 18pt tabular-nums. Per the type ramp, the macro/kcal hero values on a card are an achievement number and should be Fraunces (display-subtitle ~20–22pt) — §2.3 rule 3 ('big numerals always Fraunces'). Currently they read as dense tracker data, missing the editorial register the redesign uses for macro tile values.","f":"Render the per-serving kcal + macro values in Fraunces (display-subtitle) keeping tabular-nums, with Inter captions ('kcal','protein') below. Match the macro tile treatment used on Recipe Detail."},{"c":"functionality","s":2,"i":"The 'Publish to community' switch uses Accent.success (green) for its track/thumb. Per the colour system, success green is reserved for ring-under-budget / goal-hit / verified states; a publish toggle is not a success state. Using green here is an off-role colour use (and on an empty test account the toggle is the only colour on an otherwise monochrome form, drawing the eye to the wrong control).","f":"Switch the toggle's active colour to the brand accent (Clay/Damson) used for active controls, not Accent.success. Keep success green for genuine success/verified states only."},{"c":"spacing","s":2,"i":"Servings is a lone 80pt-wide input floating left with no stepper affordance — the recipes spec (§3.2) explicitly calls out 'bare input looks like a form field, not a deliberate stepper' and wants a boxed −/value/+ stepper. On this create form the single narrow numeric field reads as an unfinished form control and wastes the row.","f":"Replace the bare numeric input with the boxed −/[n]/+ servings stepper specified for Recipe Detail (#F6F5F2 boxed value, hairline border, 32pt buttons), shared as one component across create + detail."}]},{"key":"macro-ring","model":"sonnet","files":["apps/mobile/components/nutrition/MacroIconRow.tsx","src/app/components/suppr/daily-ring.tsx"],"gaps":[{"c":"style","s":5,"i":"Empty calorie ring is a single flat frost-mist (#EDEAF1) track on the #F6F5F2 card — the two tones sit only ~10 luminance apart, so the ring's defining element is nearly invisible on a cold open. The largest object on the screen reads as an unfinished placeholder, not a premium hero. This is the dominant first-impression failure.","f":"On the empty state, lift the track contrast: either darken the empty track to the Sloe borderStrong (#C9C2D6) or render a subtle plum→frost gradient arc (the brand AccentWinGradient soft stops) so the ring shape is unmistakable. Pair with a hairline or 1px inner ring so the circle reads as intentional geometry, not a faint outline. Keep 'Start your day / 1,252 kcal goal' centred."},{"c":"spacing","s":3,"i":"macroTileGridGap is 12 (constants/layout.ts) — off the mobile Spacing scale (xs4·sm8·md16·lg20·xl24). The Figma/design-system between-tile grid gap is md (16). 12 is a legacy v49-density carryover and breaks the 4pt rhythm against the rest of the screen.","f":"Set macroTileGridGap to Spacing.md (16) to match the design-system 'between-tile gap in grids = md' rule, or Spacing.sm (8) if a tighter grid is intended — but not a bare 12. Re-verify the 48%/48% tile widths still fit with the new gap."},{"c":"functionality","s":3,"i":"Macro tiles drop the spec'd per-tile caption. today.md §3.3 and §4 require 'X g remaining' (success) / 'X g over' (amber) under each tile; the shipped TodayDashboardMacroTiles renders only value, '/ target', and a bar — no remaining/over line. The user loses the at-a-glance 'how much left' read that the spec calls the warm-coaching payoff, and over-budget macros have no amber text signal (only the bar, which never flips colour by design).","f":"Add the caption row beneath the bar: 'N g remaining' in Accent.success when current<target, 'N g over' in Accent.warningSolid (amber, AA-safe as text) when over — per the locked macro over-budget rule. For referenceOnly macros (sugar/sodium) keep the muted 'ref' treatment, no remaining claim."},{"c":"typography","s":2,"i":"On an empty account the serif '0g' macro values (Type.title 20px Newsreader) are the heaviest typographic element in the lower fold and read as a row of zeros — the editorial serif numeral, which is meant to celebrate a real achievement number, instead amplifies emptiness. Hierarchy inverts: the empty hero ring is faint while four serif zeros shout.","f":"Soften the zero state: render '0' (or '—') at textTertiary/muted, or de-weight the value colour until current>0, so the serif numeral earns its weight only when there is data. Pairs with the empty-ring lift fix to rebalance the cold-open hierarchy."},{"c":"parity","s":3,"i":"Web hero ring (src/app/components/suppr/today-hero-ring.tsx) renders an extra visible text button 'Show macro rings / Hide macro rings' (MACRO_RING_TOGGLE) below the ring; mobile (TodayHeroRing) has no equivalent — macro-ring expand is long-press only. The two surfaces present a different control set for the same feature, an undocumented divergence.","f":"Decide one pattern and ship it both places: either add the same labelled toggle on mobile (it also satisfies today.md §3.2 / §2 accessibility — long-press needs a tap-accessible equivalent), or remove it from web for parity. Given the spec's accessibility requirement, adding the visible toggle to mobile is the correct direction."},{"c":"parity","s":2,"i":"Under-ring forward coach line ('Room for {meal}…' / 'About N kcal left… No rush.') is mobile-only — TodayDeficitInsight has no web render even though the copy + nextUnloggedMealSlot helpers already live in @suppr/shared/copy/today. today.md §6 documents this as an intentional carve-out, but the capture's coach line is one of the most premium warm-coaching touches on Today and web Today shows nothing equivalent.","f":"Track it explicitly rather than leaving it as a silent carve-out: it is documented in today.md §6.3 so it is not drift, but the shared helpers mean web can adopt the identical line cheaply. Confirm the carve-out is still intended or add the web render at Today parity; do not reimplement copy/slot logic — import the shared helpers."},{"c":"functionality","s":2,"i":"Empty meal slots show no guidance. today.md §3.4 specs Lifesum-style 'Recommended for {slot}: ~N kcal' on empty slots for users with logging history (a calm nudge, never a block). The shipped meals section is silent on empty slots — a missed warm-coaching moment that the 'permission not restriction' positioning calls for. (Not visible in this empty capture but confirmed against the meals section spec checklist.)","f":"Add the spec'd empty-slot guidance line (text-xs sans, muted sage) derived from target × typical meal distribution (breakfast 25% / lunch 35% / dinner 30% / snacks 10%), suppressed on first-ever use. Behind the redesign flag per the visual-change rule."},{"c":"style","s":3,"i":"Ring card uses lift='flat' (Elevation.card no-op) so the hero sits with zero elevation on the page; the design-system default resting card is now cardSoft (the 0.16/18px plum penumbra Grace explicitly tuned because 'cards blend into the background'). The hero — the single most important card — is the one that should read most lifted, yet it is explicitly flat, which on the near-tonal #F6F5F2-on-#FFFFFF pairing makes the whole top of the screen read as one undifferentiated slab.","f":"Re-evaluate lift='flat' on the hero: either move it to lift='soft' (cardSoft) so it separates from the page like every other resting card, or confirm flat is deliberate for the hero only and document why. Given Grace's 'sim cards blending' note, soft is the likely correct default."},{"c":"photography","s":1,"i":"No Sloe FLUX imagery anywhere on the visible cold-open. This is correct for an empty account (north-star photo hero is empty-day-below-meals and the meals are empty), so it is not a bug — but it means the premium editorial-photography differentiator (the spec's stated viral/retention surface, today.md §3.5) is entirely absent from the first screen a returning user sees, leaving the cold-open feeling like a pure tracker.","f":"No fix on this capture (judging chrome on an empty account). Verify on a populated account that the north-star card renders the hyperreal @thelittleplantation-style dish photo with the warm gradient/monogram fallback hierarchy, never a flat/placeholder tile."},{"c":"functionality","s":5,"i":"STALE CAPTURE — the rendered card does not match HEAD. The PNG shows a 2-line macro block (line 1 '312 kcal · 55g protein', line 2 '4g · 8g', then '4 servings') with an OLD icon set (flame / meat-drumstick / fork-knife / wheat). HEAD's working tree (uncommitted: library.tsx +93, MacroIconRow.tsx +16) renders a SINGLE wrapping MacroIconRow with showMacroLetters=false, emphasiseProtein (heavier ink protein), Dumbbell protein icon, plus a separate '★ saves · N min' meta row that falls back to servings. The dev client was not reloaded against the working tree, so every card-level finding from this pixel is unverifiable. This is the documented stale-dev-client-bundle trap.","f":"Reload the dev client against the current working tree (terminate + relaunch — Fast Refresh is not enough after StyleSheet/module changes) and re-capture library.png before drawing any card-level conclusions; the harness should hard-fail when bundle != HEAD (ENG-769). Re-audit the card from the fresh capture."},{"c":"photography","s":4,"i":"Bottom-right card is a COLD empty cream tile — a faint sage fork/spoon RecipeHeroFallback glyph on flat cream, with a bookmark dot but no title/photo above the fold. Next to two warm editorial dish photos it reads as a broken/loading card, not an intentional fallback. §11.4 wants sage→cream gradient + cuisine glyph, but at this size on a near-empty account it still undersells vs Julienne's all-photo gallery.","f":"Confirm RecipeHeroFallback renders the sage→cream GRADIENT (not flat cream) at card size and the cuisine glyph is sized/centred to read as deliberate. For seed/curated recipes ensure a real FLUX editorial photo is generated so the gallery is photo-dense; reserve the fallback for genuinely image-less user imports."},{"c":"typography","s":2,"i":"Fractional / off-ramp font sizes on the card. macroValue fontSize 11.5 (no 11.5 in the ramp; caption is 11-12); MacroIconRow Chunk hardcodes fontSize 12 inline. Card title is Newsreader_500Medium 15pt — recipes.md §0 'title' role and the cross-cutting DS §2 treat recipe names as an editorial moment, so 500/15 sits at the light end and slightly undersells the editorial register vs Julienne.","f":"Replace 11.5 with a ramp token (12pt caption) and route Chunk's inline 12 through the same caption token. Consider bumping the card title to Newsreader/Fraunces 600 at 15-16pt for more editorial weight while keeping the 2-line clamp."},{"c":"parity","s":3,"i":"Web and iOS Library cards have diverged. iOS uses the shared MacroIconRow (icon+value chunks, single wrapping row). Web mobile-grid hand-rolls its own macro span row (raw 11.5px text, gap-x-2/gap-y-0.5) instead of the RN gap:10 rhythm. Web DESKTOP grid is an entirely different card (4:3 hero, kind badge Saved/Your recipe/Imported, kcal-pill overlay, fit-% pill, 'Create your own version' button) with NO iOS equivalent — iOS has no fit-% pill and no kind badge.","f":"Pick one canonical mobile card and make web's mobile-grid consume the same macro primitive (port MacroIconRow or a shared macro-chip-row to web) so gap/size/weight match. Reconcile the desktop-only fit-% pill + kind badge + 'Create your own version' against iOS — add to iOS or document as an explicit desktop carve-out; today it is silent drift."},{"c":"functionality","s":2,"i":"Sort is a blind CYCLE. The count-line 'Recent' chip cycles Recent->Calories->Protein on each tap with no menu — recipes.md §2.1 flags this exact weakness and §3.1 calls for a 'Sort: {label}' chip opening a 3-option action sheet. The chip shows the current label (good) but tapping silently re-cycles, so reaching 'Protein' from 'Recent' requires guessing the order.","f":"Replace cycleSort with an action-sheet picker (Recent / Most calories / Most protein) per §3.1, keeping the current-sort label on the chip. Mirror on web (cycleSort) for parity."},{"c":"spacing","s":2,"i":"Card body vertical rhythm is uneven: cardBody gap 4 plus per-child overrides macroRow marginTop 2 and metaRow marginTop 4, so title->macro->meta spacing stacks inconsistently rather than on one rhythm.","f":"Use a single consistent vertical gap on cardBody (gap: Spacing.xs = 4) and drop the marginTop 2/4 child overrides so title, macro row, and meta row sit on a uniform 4pt rhythm; verify in a fresh capture."},{"c":"style","s":2,"i":"Category pills, count-line quiet controls, and the search field all share a near-identical cream/transparent + hairline treatment, so the filter row reads flat / low-hierarchy on white. The selected pill's soft aubergine tint fill + aubergine ink (Sloe §7) is calm but low-contrast at small size and easy to miss vs Julienne's clearer active filter.","f":"Verify the active category pill's aubergine-soft fill clears 3:1 on white and reads distinctly from inactive pills in a fresh capture; if subtle, give the active pill a primarySolid hairline border so the current filter is unmistakable."},{"c":"style","s":1,"i":"Library auto-redirects to Discover at savedCount=0 (useFocusEffect router.replace), so on a near-empty account the polished dashed-cream emptySlab (frost-mist badge, serif heading, stacked CTAs) is effectively unreachable in the default flow — the only first impression is Discover, and the empty-state polish is invisible.","f":"Confirm ENG-100 redirect is still intended; if so, document the emptySlab as a fallback-only state (deep-link/cold-open edge) or prune the redundant branch so the polish effort isn't dead code."}]}]

const SCHEMA = {
  type:'object', additionalProperties:false,
  required:['cluster','filesEdited','ported','skippedRedundant','notes'],
  properties:{
    cluster:{type:'string'},
    filesEdited:{type:'array',items:{type:'string'}},
    ported:{type:'array',items:{type:'object',additionalProperties:false,required:['fix','file'],properties:{fix:{type:'string'},file:{type:'string'}}},description:'gap-fixes I added to the aubergine version'},
    skippedRedundant:{type:'array',items:{type:'string'},description:'gap-fixes aubergine ALREADY had — skipped'},
    notes:{type:'string'},
  },
}

phase('Reconcile')

const results = await parallel(CLUSTERS.map((c)=> ()=>
  agent([
    'You are reconciling TWO parallel work-streams on the Sloe app for ONE cluster of files. The goal: the AUBERGINE redesign (currently in the working tree) is the canonical base; layer in ONLY the premium-parity gap-fixes from my fix-sweep that aubergine does NOT already have. NEVER downgrade or revert anything aubergine did.',
    '',
    'CLUSTER: '+c.key,
    'FILES: '+c.files.join(', '),
    '',
    'For EACH file, read THREE versions:',
    '  1. CURRENT (aubergine base, canonical) — just Read the file at its path.',
    '  2. MY-SWEEP version — run: git show claude-fix-sweep-snapshot:<path>',
    '  3. CLAY-BASE (what my sweep diffed FROM) — run: git show HEAD:<path>',
    'My sweep\'s intended change = (MY-SWEEP minus CLAY-BASE). Apply ONLY the parts of that change that are MISSING from CURRENT (aubergine), editing the CURRENT file in place.',
    '',
    'The gap-fixes my sweep was implementing for this surface (so you know intent):',
    ...c.gaps.sort((a,b)=>b.s-a.s).map((x,i)=>(i+1)+'. [sev '+x.s+' · '+x.c+'] '+x.i+'  >> FIX: '+x.f),
    '',
    'HARD RULES:',
    '1. AUBERGINE WINS ON CONFLICT. If aubergine already satisfies a gap (e.g. already serif, already on-scale spacing, already the bug-fix), SKIP my version — list it in skippedRedundant. Do not re-apply.',
    '2. TOKENS ONLY: serif via Type.title/headline/display/heroValue or FontFamily.serif*; spacing via Spacing.*; never hardcode a fontFamily string or an off-scale literal. NEVER edit constants/theme.ts or theme.css.',
    '3. COLOUR IS AUBERGINE (#3B2A4D accent, clay=carbs only). Never reintroduce clay-as-accent. If my-sweep version has any clay accent, do NOT port it.',
    '4. PRESERVE every aubergine improvement in the file. Your diff vs CURRENT must ADD gap-fixes, never remove aubergine work.',
    '5. For test files: update the test to match the merged source (keep aubergine assertions + add my sweep\'s new assertions where the behaviour is new). Do not delete aubergine test coverage.',
    '6. Do NOT run tsc/build/full suites. Read/Grep/git-show freely.',
    '',
    'Return the structured result: what you ported (with file), what you skipped as already-in-aubergine, and notes on anything ambiguous.',
  ].join('\n'),
  { label:'reconcile:'+c.key, phase:'Reconcile', model:c.model, agentType:'executor', schema:SCHEMA }).then(v=> v?{...v,cluster:c.key}:{cluster:c.key,error:true})
))

const clean=results.filter(r=>r&&!r.error)
const totalPorted=clean.reduce((n,r)=>n+(r.ported||[]).length,0)
const totalSkipped=clean.reduce((n,r)=>n+(r.skippedRedundant||[]).length,0)
const files=[...new Set(clean.flatMap(r=>r.filesEdited||[]))]
log('Reconciled '+clean.length+'/'+CLUSTERS.length+' clusters — '+totalPorted+' fixes ported, '+totalSkipped+' skipped as already-in-aubergine, '+files.length+' files edited')
return { perCluster: clean, totalPorted, totalSkipped, files, failed: results.filter(r=>!r||r.error).map(r=>r&&r.cluster) }
